changeSet.sql:
CREATE TABLE goals ( id UUID PRIMARY KEY, tenant_id UUID NOT NULL, employee_id UUID NOT NULL, title VARCHAR(255) NOT NULL, description TEXT, goal_type VARCHAR(50), category VARCHAR(100), target_value DECIMAL(19,2), current_value DECIMAL(19,2), measurement_unit VARCHAR(50), start_date DATE NOT NULL, due_date DATE NOT NULL, status VARCHAR(50) DEFAULT 'DRAFT', progress_percentage INT DEFAULT 0, parent_goal_id UUID, weight INT DEFAULT 100, created_by UUID, approved_by UUID, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL, version BIGINT );
CREATE INDEX idx_goals_tenant ON goals(tenant_id); CREATE INDEX idx_goals_employee ON goals(employee_id); CREATE INDEX idx_goals_status ON goals(status);
ALTER TABLE goals ADD CONSTRAINT fk_goals_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE; ALTER TABLE goals ADD CONSTRAINT fk_goals_employee FOREIGN KEY (employee_id) REFERENCES employees(id) ON DELETE CASCADE; ALTER TABLE goals ADD CONSTRAINT fk_goals_parent FOREIGN KEY (parent_goal_id) REFERENCES goals(id) ON DELETE CASCADE;
